INSERT INTO threads VALUES('019db3bc-2ce1-7461-bc65-c7e1ac58509a','C:\Users\Li\.codex\sessions\2026\04\22\rollout-2026-04-22T13-49-07-019db3bc-2ce1-7461-bc65-c7e1ac58509a.jsonl',1776836947,1776837035,'vscode','custom','\\?\C:\Users\Li\Documents\Codex\2026-04-22-llamacloud-sdk-api-import-asyncio-import','分析异步批量文档解析脚本','{"type":"workspace-write","writable_roots":["C:\\Users\\Li\\Documents\\Codex"],"network_access":false,"exclude_tmpdir_env_var":false,"exclude_slash_tmp":false}','on-request',21645,1,0,NULL,NULL,NULL,NULL,'0.123.0-alpha.5',replace(replace('你好，分析这段代码"""\015\012异步批量文档解析脚本 - 使用 LlamaCloud SDK\015\012支持多API轮换、断点续传、智能重试\015\012"""\015\012\015\012import asyncio\015\012import os\015\012import re\015\012import json\015\012from pathlib import Path\015\012from typing import List, Dict, Optional\015\012from datetime import datetime\015\012from dotenv import load_dotenv\015\012from llama_cloud import LlamaCloud\015\012\015\012# 加载环境变量\015\012load_dotenv()\015\012\015\012\015\012class AsyncBatchParser:\015\012    def __init__(\015\012        self,\015\012        input_folder: str,\015\012        max_concurrent: int = 3,\015\012        max_retries: int = 3,\015\012        base_delay: float = 2.0,\015\012        progress_file: str = "parse_progress.json"\015\012    ):\015\012        self.input_folder = Path(input_folder)\015\012        self.max_concurrent = max_concurrent\015\012        self.max_retries = max_retries\015\012        self.base_delay = base_delay\015\012        self.progress_file = self.input_folder / progress_file\015\012        \015\012        # 加载所有可用的API密钥\015\012        self.api_keys = self._load_api_keys()\015\012        self.current_api_index = 0\015\012        self.api_lock = asyncio.Lock()\015\012        \015\012        # 加载进度\015\012        self.progress = self._load_progress()\015\012        \015\012        # 统计信息\015\012        self.stats = {\015\012            "total": 0,\015\012            "success": 0,\015\012            "failed": 0,\015\012            "skipped": 0,\015\012            "api_usage": {key: 0 for key in self.api_keys}\015\012        }\015\012    \015\012    def _load_api_keys(self) -> List[str]:\015\012        """从环境变量加载所有API密钥"""\015\012        keys = []\015\012        \015\012        # 加载主密钥\015\012        main_key = os.getenv("LLAMA_CLOUD_API_KEY")\015\012        if main_key:\015\012            keys.append(main_key)\015\012        \015\012        # 加载编号密钥 (LLAMA_CLOUD_API_KEY2, LLAMA_CLOUD_API_KEY3, ...)\015\012        i = 2\015\012        while True:\015\012            key = os.getenv(f"LLAMA_CLOUD_API_KEY{i}")\015\012            if not key:\015\012                break\015\012            keys.append(key)\015\012            i += 1\015\012        \015\012        if not keys:\015\012            raise ValueError("未找到任何API密钥！请在.env文件中设置 LLAMA_CLOUD_API_KEY")\015\012        \015\012        return keys\015\012    \015\012    def _load_progress(self) -> Dict:\015\012        """加载进度文件"""\015\012        if self.progress_file.exists():\015\012            try:\015\012                with open(self.progress_file, ''r'', encoding=''utf-8'') as f:\015\012                    return json.load(f)\015\012            except:\015\012                pass\015\012        return {"completed": [], "failed": []}\015\012    \015\012    def _save_progress(self):\015\012        """保存进度"""\015\012        with open(self.progress_file, ''w'', encoding=''utf-8'') as f:\015\012            json.dump(self.progress, f, indent=2, ensure_ascii=False)\015\012    \015\012    async def _get_next_api_key(self) -> tuple[str, int]:\015\012        """获取下一个可用的API密钥（线程安全）"""\015\012        async with self.api_lock:\015\012            key = self.api_keys[self.current_api_index]\015\012            index = self.current_api_index\015\012            self.current_api_index = (self.current_api_index + 1) % len(self.api_keys)\015\012            return key, index\015\012    \015\012    def _get_client(self, api_key: str) -> LlamaCloud:\015\012        """创建 LlamaCloud 客户端"""\015\012        return LlamaCloud(api_key=api_key)\015\012    \015\012    async def parse_document(\015\012        self,\015\012        pdf_path: Path,\015\012        semaphore: asyncio.Semaphore\015\012    ) -> Dict:\015\012        """解析单个文档"""\015\012        async with semaphore:\015\012            file_name = pdf_path.name\015\012            \015\012            # 检查是否已完成\015\012            if file_name in self.progress["completed"]:\015\012                self.stats["skipped"] += 1\015\012                print(f"[{self.stats[''total'']}/{len(self.pdf_files)}] ⊘ {file_name} (已跳过)")\015\012                return {"status": "skipped", "file": file_name}\015\012            \015\012            # 重试逻辑\015\012            last_error = None\015\012            for attempt in range(self.max_retries):\015\012                try:\015\012                    # 获取API密钥\015\012                    api_key, api_index = await self._get_next_api_key()\015\012                    client = self._get_client(api_key)\015\012                    \015\012                    # 上传文件\015\012                    with open(pdf_path, ''rb'') as f:\015\012                        file = await asyncio.to_thread(\015\012                            client.files.create,\015\012                            file=f,\015\012                            purpose="parse"\015\012                        )\015\012                    \015\012                    # 解析文档\015\012                    result = await asyncio.to_thread(\015\012                        client.parsing.parse,\015\012                        file_id=file.id,\015\012                        tier="agentic",\015\012                        version="latest",\015\012                        expand=["markdown"]\015\012                    )\015\012                    \015\012                    # 处理结果\015\012                    pages = []\015\012                    for page in result.markdown.pages:\015\012                 