           }\015\012    \015\012    async def run(self):\015\012        """运行批量解析"""\015\012        # 查找所有PDF文件\015\012        self.pdf_files = sorted(self.input_folder.glob("*.pdf"))\015\012        self.stats["total"] = len(self.pdf_files)\015\012        \015\012        if not self.pdf_files:\015\012            print(f"❌ 在 {self.input_folder} 中未找到PDF文件")\015\012            return\015\012        \015\012        print(f"找到 {len(self.pdf_files)} 个文件")\015\012        print(f"🔑 使用 {len(self.api_keys)} 个API密钥")\015\012        print(f"⚡ 最大并发数: {self.max_concurrent}")\015\012        print(f"🔄 最大重试次数: {self.max_retries}")\015\012        print("=" * 70)\015\012        \015\012        # 创建信号量控制并发\015\012        semaphore = asyncio.Semaphore(self.max_concurrent)\015\012        \015\012        # 并发处理所有文件\015\012        start_time = datetime.now()\015\012        tasks = [self.parse_document(pdf, semaphore) for pdf in self.pdf_files]\015\012        results = await asyncio.gather(*tasks, return_exceptions=True)\015\012        end_time = datetime.now()\015\012        \015\012        # 打印统计报告\015\012        duration = (end_time - start_time).total_seconds()\015\012        print("\n" + "=" * 70)\015\012        print("📊 处理完成统计")\015\012        print("=" * 70)\015\012        print(f"总文件数: {self.stats[''total'']}")\015\012        print(f"✓ 成功: {self.stats[''success'']}")\015\012        print(f"✗ 失败: {self.stats[''failed'']}")\015\012        print(f"⊘ 跳过: {self.stats[''skipped'']}")\015\012        print(f"⏱ 总耗时: {duration:.1f}秒")\015\012        print(f"⚡ 平均速度: {duration/max(self.stats[''success''], 1):.1f}秒/文件")\015\012        \015\012        print("\n🔑 API使用统计:")\015\012        for i, (key, count) in enumerate(self.stats["api_usage"].items(), 1):\015\012            masked_key = key[:8] + "..." + key[-4:] if len(key) > 12 else key\015\012            print(f"  API#{i} ({masked_key}): {count} 次")\015\012        \015\012        if self.progress["failed"]:\015\012            print(f"\n❌ 失败的文