   tools: list[dict] = field(default_factory=list)\012+    _handlers: dict[str, Callable[..., str]] = field(default_factory=dict)\012+\012+    def register(self, tool_defs: list[dict], handlers: dict[str, Callable[..., str]]) -> None:\012+        self.tools = tool_defs\012+        self._handlers = handlers\012+\012+    def call_tool(self, tool_name: str, args: dict) -> str:\012+        handler = self._handlers.get(tool_name)\012+        if handler is None:\012+            return f"MCP error: unknown tool {tool_name!r}"\012+        try:\012+            return str(handler(**args))\012+        except Exception as exc:\012+            return f"MCP error: {type(exc).__name__}: {exc}"\012+\012+\012+mcp_clients: dict[str, MCPClient] = {}\012+_DISALLOWED_CHARS = re.compile(r"[^a-zA-Z0-9_-]")\012+\012+\012+def normalize_mcp_name(name: str) -> str:\012+    return _DISALLOWED_CHARS.sub("_", name.strip())\012+\012+\012+def _mock_docs_server() -> MCPClient:\012+    client = MCPClient("docs")\012+    client.register(\012+        tool_defs=[\012+            {\012+                "name": "search",\012+                "description": "Search documentation. (readOnly)",\012+                "inputSchema": {\012+                    "type": "object",\012+                    "properties": {"query": {"type": "string"}},\012+                    "required": ["query"],\012+                },\012+            },\012+            {\012+                "name": "get_version",\012+                "description": "Get the docs API version. (readOnly)",\012+                "inputSchema": {"type": "object", "properties": {}, "required": []},\012+            },\012+        ],\012+        handlers={\012+            "search": lambda query: f"[docs] Found 3 result(s) for {query!r}",\012+            "get_version": lambda: "[docs] API v2.1.0",\012+        },\012+    )\012+    return client\012+\012+\012+def _mock_deploy_server() -> MCPClient:\012+    client = <truncated omitted_approx_tokens="428" />orted(MOC