   \"name\": \"connect_mcp\",\n+    \"description\": \"Connect to a mock MCP server and discover its tools. Available servers: docs, deploy.\",\n+    \"input_schema\": {\n+        \"type\": \"object\",\n+        \"properties\": {\"name\": {\"type\": \"string\"}},\n+        \"required\": [\"name\"],\n+    },\n+}\n+\n+\n+def run_connect_mcp(name: str) -> str:\n+    server_name = name.strip()\n+    if server_name in mcp_clients:\n+        return f\"MCP server {server_name!r} already connected\"\n+\n+    factory = MOCK_SERVERS.get(server_name)\n+    if factory is None:\n+        return f\"Unknown MCP server {server_name!r}. Available: {'', ''.join(sorted(MOCK_SERVERS))}\"\n+\n+    client = factory()\n+    mcp_clients[server_name] = client\n+    tool_names = \", \".join(tool[\"name\"] for tool in client.tools)\n+    print(f\"\\033[35m[mcp:connect] {server_name}: {tool_names}\\033[0m\")\n+    return f\"Connected to MCP server {server_name!r}. Discovered tools: {tool_names}\"\n+\n+\n+def assemble_tool_pool(base_tools: list[dict], base_handlers: dict) -> tuple[list[dict], dict]:\n+    tools = list(base_tools)\n+    handlers = dict(base_handlers)\n+\n+    for server_name, client in mcp_clients.items():\n+        safe_server = normalize_mcp_name(server_name)\n+        for tool_def in client.tools:\n+            original_name = tool_def[\"name\"]\n+            safe_tool = normalize_mcp_name(original_name)\n+            prefixed_name = f\"mcp__{safe_server}__{safe_tool}\"\n+            tools.append({\n+                \"name\": prefixed_name,\n+                \"description\": tool_def.get(\"description\", \"\"),\n+                \"input_schema\": tool_def.get(\"inputSchema\", {\"type\": \"object\", \"properties\": {}}),\n+            })\n+            handlers[prefixed_name] = (\n+                lambda *, c=client, t=original_name, **kwargs: c.call_tool(t, kwargs)\n+            )\n+\n+    return tools, handlers\n+\n+\n+def list_mcp_servers_overview() -> str:\n+    if not mcp_