rite_gatt_char_compat(client, tx_uuid, b"Z", response=response)\r\012 273:                     await asyncio.sleep(0.03)\r\012 274:             except Exception:\r\012 275:                 pass\r\012 276: \r\012 277:             stdin_task.cancel()\r\012 278:             if args.notify and rx_uuid:\r\012 279:                 try:\r\012 280:                     await _stop_notify_compat(client, rx_uuid)\r\012\012\012[46] assistant: 速度帧在固件里会把 `RC_Velocity` 设成 `speed/1000`，所以脚本里采用 `{0:500}` 这种帧；之后 `A/E/G/C` 只是选择方向，真正速度来自这个 `RC_Velocity`。这意味着“固定距离”在电脑端会是开环的 `速度 x 时间`，会受启动平滑和地面摩擦影响，但正好符合你现在要的最基础版本。\012\012[47] tool apply_patch call: *** Begin Patch\012*** Update File: work/bt04_bleak_console.py\012@@\012         # Optional unlock sequence (required by some WHEELTEC chassis firmware on USART3).\012         if args.unlock:\012             for _ in range(6):\012                 await _write_gatt_char_compat(client, tx_uuid, b"A", response=response)\012                 await asyncio.sleep(0.02)\012-\012-        print(\012-            "Commands:\n"\012-            "- Type a single letter like A/B/C.../Z to start streaming it continuously.\n"\012-            "- Type a longer string like {Q:P} to send it once.\n"\012-            "- Type ''help'' to print this message again.\n"\012-            "- Type ''quit'' or press Ctrl+C to exit (script will try to send Z before disconnect).\n"\012-        )\012-\012-        # Keep streaming the last single-letter command. Default to stop.\012-        current_stream: bytes = b"Z"\012+            for _ in range(6):\012+                await _write_gatt_char_compat(client, tx_uuid, b"Z", response=response)\012+                await asyncio.sleep(0.03)\012+\012+        async def _send_speed_for(cmd_char: str) -> None:\012+            if args.no_speed_frame:\012+                return\012+            speed = turn_speed if cmd_char in TURN_COMMANDS else move_speed\012+            payload = _speed_frame(speed)\012+            if payload is None:\