message: str = ""\015\012    error: str = ""\015\012\015\012    def get_field(self, name: str) -> str:\015\012        if name == "tool":\015\012            return self.tool_name\015\012        if name == "event":\015\012            return self.event_name\015\012        if name.startswith("args."):\015\012            key = name[5:]\015\012            value = self.tool_args.get(key, "")\015\012            return str(value) if value else ""\015\012        return ""\015\012\015\012    def expand(self, template: str) -> str:\015\012        result = template\015\012        result = result.replace("$EVENT", self.event_name)\015\012        result = result.replace("$TOOL_NAME", self.tool_name)\015\012        result = result.replace("$FILE_PATH", self.file_path)\015\012        result = result.replace("$MESSAGE", self.message)\015\012        result = result.replace("$ERROR", self.error)\015\012        for key, value in self.tool_args.items():\015\012            result = result.replace(f"$TOOL_ARGS.{key}", str(value))\015\012        return result\015\012\015\012\015\012class ToolRejectedError(Exception):\015\012    def __init__(self, tool: str, reason: str, hook_id: str) -> None:\015\012        self.tool = tool\015\012        self.reason = reason\015\012        self.hook_id = hook_id\015\012        super().__init__(f"Tool ''{tool}'' rejected by hook ''{hook_id}'': {reason}")\015\012\012\012[75] tool exec call: const r = await tools.exec_command({\012  cmd: "rg -n ''except .*LLM|RetryEvent|client.stream|RateLimit|NetworkError'' mewcode\\agent.py mewcode\\app.py mewcode\\__main__.py",\012  shell:"powershell",workdir:"E:\\py_project\\Braincode",yield_time_ms:10000,max_output_tokens:5000\012});\012text(r.output);\012\012\012[76] tool exec result: Script completed\012Wall time 0.5 seconds\012Output:\012\012mewcode\__main__.py:120:        RetryEvent,\012mewcode\__main__.py:325:        elif isinstance(event, RetryEvent):\012mewcode\app.py:30:    RetryEvent,\015\012mewcode\app.py:1253: