INSERT INTO thread_dynamic_tools VALUES('019db3bc-2ce1-7461-bc65-c7e1ac58509a',0,'automation_update','Render an automation create/edit/view card in the app, or delete an existing automation. Use this when the user explicitly asks for automation, a recurring run, or a repeated task. Use mode=view to show an existing automation, mode=create to immediately create a new automation, mode=update to immediately update an existing automation, and mode=delete to immediately delete an existing automation.','{"type":"object","properties":{"id":{"type":"string","description":"Automation id. Required for mode=view, mode=update, mode=delete, and mode=suggested_update. Omit for mode=create and mode=suggested_create."},"mode":{"type":"string","description":"One of view, create, update, delete, suggested_create, or suggested_update."},"kind":{"type":"string","description":"One of cron or heartbeat. Required for create, update, suggested_create, and suggested_update. Cron automations are standalone recurring jobs; heartbeat automations are proactive follow-ups attached to a thread."},"name":{"type":"string"},"prompt":{"type":"string","description":"The automation prompt. Describe only the task itself; do not include schedule or workspace details."},"rrule":{"type":"string","description":"RRULE schedule string. Cron automations use hourly interval or weekly schedules. Heartbeat automations attached to a thread can use minute-based intervals such as FREQ=MINUTELY;INTERVAL=30 or daily/weekly wall-clock schedules."},"cwds":{"anyOf":[{"type":"string"},{"type":"array","items":{"type":"string"}}]},"destination":{"type":"string","description":"Optional automation destination. Use thread for heartbeat automations attached to the current local thread."},"executionEnvironment":{"type":"string","description":"One of worktree or local. Cron automations only."},"localEnvironmentConfigPath":{"type":["string","null"],"description":"Optional local environment config path for worktree setup scripts. Omit to preserve the existing selection on update, or pass null to clear it. Cron automations only."},"model":{"type":"string","description":"Model to use for cron automations."},"reasoningEffort":{"type":"string","description":"Reasoning effort to use for cron automations. One of none, minimal, low, medium, high, or xhigh."},"targetThreadId":{"type":"string","description":"Target thread id for heartbeat automations. Prefer destination=thread when the automation should attach to the current local thread."},"status":{"type":"string","description":"One of ACTIVE or PAUSED."}},"additionalProperties":false}',0,NULL);
INSERT INTO thread_dynamic_tools VALUES('019db3bc-2ce1-7461-bc65-c7e1ac58509a',1,'read_thread_terminal','Read the current app terminal output for this desktop thread. Use it when you need shell output or the current prompt before deciding the next step. This tool takes no arguments.','{"type":"object","properties":{},"additionalProperties":false}',0,NULL);
