INSERT INTO thread_dynamic_tools VALUES('019e1541-fddf-79f3-aea0-27e20449fa28',0,'automation_update','Create, update, view, or delete recurring automations in the Codex app. Use this when the user asks for an automation, recurring run, repeated task, reminder, follow-up, monitor, or asks you to watch something, keep an eye on it, check back later, wake up later, notify them, or keep working later. Cron automations run as standalone jobs against workspaces. Heartbeat automations are proactive follow-ups attached to the current local thread. Prefer heartbeats for requests to continue this thread later, especially below one hour. Use suggested_create or suggested_update when proposing a worktree automation with a local environment setup config so the user can review it before it is saved. Never write raw automation directives by hand, show raw RRULE strings to the user, or create a workaround cron automation for a thread heartbeat unless the user explicitly asks for that. For requests about existing automations, inspect $CODEX_HOME/automations/*/automation.toml to find matching automation ids by name or prompt. Prefer updating an existing automation over creating a duplicate. For updates, preserve existing fields unless the user asks to change them, and call automation_update with the resolved id and full updated fields.','{"type":"object","properties":{"id":{"type":"string","description":"Automation id. Required for mode=view, mode=update, mode=delete, and mode=suggested_update. Omit for mode=create and mode=suggested_create."},"mode":{"type":"string","description":"One of view, create, update, delete, suggested_create, or suggested_update. Use view to show an existing automation, create/update/delete to mutate immediately, and suggested_create/suggested_update to present a proposal for the user to review."},"kind":{"type":"string","description":"One of cron or heartbeat. Required for create, update, suggested_create, and suggested_update. Use cron for detached workspace jobs. Use heartbeat when the user wants this thread to wake up later and continue the conversation."},"name":{"type":"string","description":"Short human-readable automation name. If the user does not provide one, choose a concise name."},"prompt":{"type":"string","description":"The automation prompt. Describe only the task itself; do not include schedule, workspace, or thread details because those are provided separately. Keep it self-sufficient, include output expectations when useful, and do not ask it to write a file or announce nothing to do unless the user explicitly asked for that."},"rrule":{"type":"string","description":"RRULE schedule string. Interpret requested times in the user''s locale. Cron automations use hourly interval or weekly schedules. Heartbeat automations attached to a thread can use minute-based intervals such as FREQ=MINUTELY;INTERVAL=30 or daily/weekly wall-clock schedules."},"cwds":{"description":"Cron automations only. Workspace directories for the automation; can be a JSON array or comma-separated string.","anyOf":[{"type":"string"},{"type":"array","items":{"type":"string"}}]},"destination":{"type":"string","description":"Optional automation destination. Use thread for heartbeat automations attached to the current local thread."},"executionEnvironment":{"type":"string","description":"One of worktree or local. Cron automations only."},"localEnvironmentConfigPath":{"type":["string","null"],"description":"Optional local environment config path for worktree setup scripts. Immediate worktree create calls with a non-null value and immediate worktree update calls that preserve or set a setup config are rejected; use suggested_create/suggested_update for user review. Pass null to clear or run without setup. Cron automations only."},"model":{"type":"string","description":"Model to use for cron automations."},"reasoningEffort":{"type":"string","description":"Reasoning effort to use for cron automations. One of none, minimal, low, medium, high, or xhigh."},"targetThreadId":{"type":"string","description":"Target thread id for heartbeat automations. Prefer destination=thread for the current local thread instead of inventing or copying raw thread ids."},"status":{"type":"string","description":"One of ACTIVE or PAUSED. Default to ACTIVE unless the user asks to start paused."}},"additionalProperties":false}',0,'codex_app');
INSERT INTO thread_dynamic_tools VALUES('019e1541-fddf-79f3-aea0-27e20449fa28',1,'read_thread_terminal','Read the current app terminal output for this desktop thread. Use it when you need shell output or the current prompt before deciding the next step. This tool takes no arguments.','{"type":"object","properties":{},"additionalProperties":false}',0,NULL);
INSERT INTO thread_dynamic_tools VALUES('019e1541-fddf-79f3-aea0-27e20449fa28',2,'load_workspace_dependencies','Locate the configured bundled workspace dependency runtime paths for this local desktop thread, including Node.js, Python, and useful libraries for working with spreadsheets, slide decks, Word documents, and PDFs. This is read-only and takes no arguments.','{"type":"object","properties":{},"additionalProperties":false}',0,NULL);
