INSERT INTO thread_dynamic_tools VALUES('019e83d4-1377-7671-8720-7f178a6cbf33',3,'create_thread','Create a new Codex thread in the background. Use project targets for repo-scoped work and projectless targets for general tasks. Project targets must choose a local or worktree environment.','{"type":"object","additionalProperties":false,"properties":{"prompt":{"type":"string","description":"Initial prompt for the new thread."},"target":{"description":"Where to create the thread.","anyOf":[{"type":"object","additionalProperties":false,"properties":{"type":{"type":"string","enum":["project"]},"projectId":{"type":"string","description":"Saved project id / workspace root."},"environment":{"description":"Where the project thread should run: directly in the saved project or in a new worktree.","anyOf":[{"type":"object","additionalProperties":false,"properties":{"type":{"type":"string","enum":["local"]}},"required":["type"]},{"type":"object","additionalProperties":false,"properties":{"type":{"type":"string","enum":["worktree"]},"startingState":{"description":"Starting state for the new worktree.","anyOf":[{"type":"object","additionalProperties":false,"properties":{"type":{"type":"string","enum":["working-tree"]}},"required":["type"]},{"type":"object","additionalProperties":false,"properties":{"type":{"type":"string","enum":["branch"]},"branchName":{"type":"string"}},"required":["type","branchName"]}]}},"required":["type"]}]}},"required":["type","projectId","environment"]},{"type":"object","additionalProperties":false,"properties":{"type":{"type":"string","enum":["projectless"]},"directoryName":{"type":"string","description":"Optional projectless output directory name."}},"required":["type"]}]},"model":{"type":"string","description":"Optional model override."},"thinking":{"type":"string","description":"Optional reasoning effort override.","enum":["low","medium","high","xhigh"]}},"required":["prompt","target"]}',1,'codex_app');
INSERT INTO thread_dynamic_tools VALUES('019e83d4-1377-7671-8720-7f178a6cbf33',4,'list_threads','List recent Codex threads in the background. Use an optional query to find a specific thread before reading or steering it.','{"type":"object","additionalProperties":false,"properties":{"query":{"type":"string","description":"Optional thread search query."},"limit":{"type":"number","description":"Maximum number of thread summaries to return."}}}',1,'codex_app');
INSERT INTO thread_dynamic_tools VALUES('019e83d4-1377-7671-8720-7f178a6cbf33',5,'read_thread','Read recent status and turn summaries for one Codex thread without opening it. Use page cursors from earlier responses to read older turns.','{"type":"object","additionalProperties":false,"properties":{"threadId":{"type":"string","description":"Thread id to inspect."},"cursor":{"type":"string","description":"Optional cursor for older turns."},"turnLimit":{"type":"number","description":"Maximum number of turns to return."},"includeOutputs":{"type":"boolean","description":"Whether to include truncated tool or command outputs."},"maxOutputCharsPerItem":{"type":"number","description":"Maximum output characters to keep for each included output item."}},"required":["threadId"]}',1,'codex_app');
INSERT INTO thread_dynamic_tools VALUES('019e83d4-1377-7671-8720-7f178a6cbf33',6,'send_message_to_thread','Send a follow-up prompt to an existing Codex thread in the background. Omit model and thinking to keep the thread''s current settings.','{"type":"object","additionalProperties":false,"properties":{"threadId":{"type":"string","description":"Thread id to continue."},"prompt":{"type":"string","description":"Follow-up prompt to send."},"model":{"type":"string","description":"Optional model override."},"thinking":{"type":"string","description":"Optional reasoning effort override.","enum":["low","medium","high","xhigh"]}},"required":["threadId","prompt"]}',1,'codex_app');
INSERT INTO thread_dynamic_tools VALUES('019e83d4-1377-7671-8720-7f178a6cbf33',7,'set_thread_pinned','Pin or unpin a Codex thread in the background.','{"type":"object","additionalProperties":false,"properties":{"threadId":{"type":"string","description":"Thread id to pin or unpin."},"pinned":{"type":"boolean","description":"Whether the thread should be pinned."}},"required":["threadId","pinned"]}',1,'codex_app');
INSERT INTO thread_dynamic_tools VALUES('019e83d4-1377-7671-8720-7f178a6cbf33',8,'set_thread_archived','Archive or unarchive a Codex thread in the background.','{"type":"object","additionalProperties":false,"properties":{"threadId":{"type":"string","description":"Thread id to archive or unarchive."},"archived":{"type":"boolean","description":"Whether the thread should be archived."},"hostId":{"type":"string","description":"Optional host id. Needed when unarchiving an unloaded thread."}},"required":["threadId","archived"]}',1,'codex_app');
INSERT INTO thread_dynamic_tools VALUES('019e83d4-1377-7671-8720-7f178a6cbf33',9,'set_thread_title','Rename a Codex thread in the background.','{"type":"object","additionalProperties":false,"properties":{"threadId":{"type":"string","description":"Thread id to rename."},"title":{"type":"string","description":"New thread title."}},"required":["threadId","title"]}',1,'codex_app');
